static inline uint32_t u32_floor_div(uint32_t a, uint32_t b) {
    return b == 0 ? 0 : (a / b);
}
}

namespace optiling {

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    Conv3dSoftmaxMaxPoolMaxPoolCustomTilingData tiling;

    const gert::Shape *x_shape = context->GetInputShape(0);
    const gert::Shape *w_shape = context->GetInputShape(1);
    if (x_shape->GetOriginShape().GetDimNum() != 5 || w_shape->GetOriginShape().GetDimNum() != 5) {
        return ge::GRAPH_FAILED;
    }

    const uint32_t N   = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(0));
    const uint32_t Cin = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(1));
    const uint32_t D   = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(2));
    const uint32_t H   = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(3));
    const uint32_t W   = static_cast<uint32_t>(x_shape->GetOriginShape().GetDim(4));

    const uint32_t Cout = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(0));
    const uint32_t Kd   = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(2));
    const uint32_t Kh   = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(3));
    const uint32_t Kw   = static_cast<uint32_t>(w_shape->GetOriginShape().GetDim(4));

    // conv3d (stride=1, pad=0, dil=1)
    const uint32_t Do = (D >= Kd) ? (D - Kd + 1) : 0;
    const uint32_t Ho = (H >= Kh) ? (H - Kh + 1) : 0;
    const uint32_t Wo = (W >= Kw) ? (W - Kw + 1) : 0;

    // two times max_pool3d(kernel=2, stride=2) => composite kernel=4, stride=4
    const uint32_t D2 = u32_floor_div(Do, 4);
    const uint32_t H2 = u32_floor_div(Ho, 4);
    const uint32_t W2 = u32_floor_div(Wo, 4);

    const uint32_t totalPos = N * D2 * H2 * W2;

    uint32_t blockDim = totalPos;
    if (blockDim < 1u) blockDim = 1u;
    if (blockDim > 24u) blockDim = 24u;  // conservative

    context->SetBlockDim(blockDim);

    tiling.set_n(N);
    tiling.set_cin(Cin);
    tiling.set_cout(Cout);
    tiling.set_d(D);
    tiling.set_h(H);
    tiling.set_w(W);
    tiling.set_kd(Kd);
    tiling.set_kh(Kh);
    tiling.set_kw(Kw);
    tiling.set_do_(Do);
    tiling.set_ho(Ho);
    tiling.set_wo(Wo);
    tiling.set_d2(D2);
    tiling.set_h2(H2);
    tiling.set_w2(W2);
    tiling.set_totalPos(totalPos);
    tiling.set_blockDim(blockDim);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

