    auto D = x.size(2);
    auto H = x.size(3);
    auto W = x.size(4);
    auto Cout = weight.size(0);
    auto Kd = weight.size(2);
    auto Kh = weight.size(3);
    auto Kw = weight.size(4);
    auto Do = (D >= Kd) ? (D - Kd + 1) : 0;
    auto Ho = (H >= Kh) ? (H - Kh + 1) : 0;
    auto Wo = (W >= Kw) ? (W - Kw + 1) : 0;
    auto D2 = Do / 4;
    auto H2 = Ho / 4;
    auto W2 = Wo / 4;

    at::Tensor result = at::empty({N, Cout, D2, H2, W2}, x.options());
    EXEC_NPU_CMD(aclnnConv3dSoftmaxMaxPoolMaxPoolCustom, x, weight, bias, result);
